   1â†’/*
   2â†’ * Todo List Application -- Main Stylesheet
   3â†’ *
   4â†’ * CSS Architecture: Cascade Layers
   5â†’ * ---------------------------------
   6â†’ * Layers control specificity order regardless of source order.
   7â†’ * Earlier layers have lower priority; later layers win ties.
   8â†’ *
   9â†’ * @layer reset     -- Normalize browser defaults
  10â†’ * @layer tokens    -- Design tokens (CSS custom properties on :root)
  11â†’ * @layer base      -- Element-level styles (body, headings, links, forms)
  12â†’ * @layer layout    -- Page-level layout (CSS Grid, containers)
  13â†’ * @layer components -- Component-specific styles (added per feature)
  14â†’ * @layer utilities -- Helper classes (visually-hidden, etc.)
  15â†’ */
  16â†’
  17â†’@layer reset, tokens, base, layout, components, utilities;
  18â†’
  19â†’/* ==========================================================================
  20â†’   RESET LAYER
  21â†’   Modern CSS reset. Removes browser inconsistencies while preserving
  22â†’   useful defaults. Based on Andy Bell's modern reset.
  23â†’   ========================================================================== */
  24â†’
  25â†’@layer reset {
  26â†’  *,
  27â†’  *::before,
  28â†’  *::after {
  29â†’    box-sizing: border-box;
  30â†’  }
  31â†’
  32â†’  * {
  33â†’    margin: 0;
  34â†’    padding: 0;
  35â†’  }
  36â†’
  37â†’  html {
  38â†’    -moz-text-size-adjust: none;
  39â†’    -webkit-text-size-adjust: none;
  40â†’    text-size-adjust: none;
  41â†’  }
  42â†’
  43â†’  body {
  44â†’    min-block-size: 100vh;
  45â†’    line-height: 1.5;
  46â†’    -webkit-font-smoothing: antialiased;
  47â†’  }
  48â†’
  49â†’  img,
  50â†’  picture,
  51â†’  video,
  52â†’  canvas,
  53â†’  svg {
  54â†’    display: block;
  55â†’    max-inline-size: 100%;
  56â†’  }
  57â†’
  58â†’  input,
  59â†’  button,
  60â†’  textarea,
  61â†’  select {
  62â†’    font: inherit;
  63â†’    color: inherit;
  64â†’  }
  65â†’
  66â†’  p,
  67â†’  h1,
  68â†’  h2,
  69â†’  h3,
  70â†’  h4,
  71â†’  h5,
  72â†’  h6 {
  73â†’    overflow-wrap: break-word;
  74â†’  }
  75â†’
  76â†’  h1,
  77â†’  h2,
  78â†’  h3,
  79â†’  h4,
  80â†’  h5,
  81â†’  h6 {
  82â†’    text-wrap: balance;
  83â†’  }
  84â†’
  85â†’  a {
  86â†’    color: inherit;
  87â†’    text-decoration-skip-ink: auto;
  88â†’  }
  89â†’
  90â†’  ul[role="list"],
  91â†’  ol[role="list"] {
  92â†’    list-style: none;
  93â†’  }
  94â†’
  95â†’  /* Remove default button styles */
  96â†’  button {
  97â†’    cursor: pointer;
  98â†’    background: none;
  99â†’    border: none;
 100â†’  }
 101â†’
 102â†’  /* Remove animations and transitions for users who prefer reduced motion */
 103â†’  @media (prefers-reduced-motion: reduce) {
 104â†’    *,
 105â†’    *::before,
 106â†’    *::after {
 107â†’      animation-duration: 0.01ms !important;
 108â†’      animation-iteration-count: 1 !important;
 109â†’      transition-duration: 0.01ms !important;
 110â†’      scroll-behavior: auto !important;
 111â†’    }
 112â†’  }
 113â†’}
 114â†’
 115â†’/* ==========================================================================
 116â†’   TOKENS LAYER
 117â†’   Design tokens as CSS custom properties on :root.
 118â†’
 119â†’   Token system:
 120â†’   - Spacing:    4px base unit, named --space-xs through --space-3xl
 121â†’   - Colors:     oklch color space for perceptual uniformity
 122â†’   - Typography: System font stack, fluid type scale with clamp()
 123â†’   - Shadows:    Three levels (sm, md, lg)
 124â†’   - Radii:      Three sizes (sm, md, lg)
 125â†’   - Transitions: Duration values for consistent animation timing
 126â†’
 127â†’   All component styles reference tokens -- no hardcoded values.
 128â†’   Token changes go through the mob with Steve Schoger's approval.
 129â†’   ========================================================================== */
 130â†’
 131â†’@layer tokens {
 132â†’  :root {
 133â†’    /* ---- Spacing Scale ----
 134â†’     * 4px base unit. Numbered primitives map to multiples of 4px.
 135â†’     * Semantic aliases below provide meaningful names for common uses.
 136â†’     * Scale: 4, 8, 12, 16, 24, 32, 48, 64, 96
 137â†’     */
 138â†’    --space-1:  0.25rem;  /* 4px */
 139â†’    --space-2:  0.5rem;   /* 8px */
 140â†’    --space-3:  0.75rem;  /* 12px */
 141â†’    --space-4:  1rem;     /* 16px */
 142â†’    --space-6:  1.5rem;   /* 24px */
 143â†’    --space-8:  2rem;     /* 32px */
 144â†’    --space-12: 3rem;     /* 48px */
 145â†’    --space-16: 4rem;     /* 64px */
 146â†’    --space-24: 6rem;     /* 96px */
 147â†’
 148â†’    /* Semantic spacing aliases */
 149â†’    --space-xs:  var(--space-1);   /* 4px */
 150â†’    --space-sm:  var(--space-2);   /* 8px */
 151â†’    --space-md:  var(--space-4);   /* 16px */
 152â†’    --space-lg:  var(--space-6);   /* 24px */
 153â†’    --space-xl:  var(--space-8);   /* 32px */
 154â†’    --space-2xl: var(--space-12);  /* 48px */
 155â†’    --space-3xl: var(--space-16);  /* 64px */
 156â†’
 157â†’    /* ---- Color Palette ----
 158â†’     * oklch color space for perceptual uniformity.
 159â†’     * Most UI is grayscale; color is for emphasis and interaction.
 160â†’     * "The grays do the heavy lifting, primary blue is supporting cast."
 161â†’     *
 162â†’     * oklch(Lightness Chroma Hue)
 163â†’     * - Lightness: 0 (black) to 1 (white)
 164â†’     * - Chroma: 0 (gray) to ~0.4 (most saturated)
 165â†’     * - Hue: 0-360 degrees
 166â†’     */
 167â†’
 168â†’    /* Neutral grays -- zero chroma for true neutrals
 169â†’     *
 170â†’     * Contrast ratios vs white (#fff):
 171â†’     *   gray-50 to gray-300: decorative/border use only, NOT for text
 172â†’     *   gray-400 (~0.71): ~3:1  -- large text/UI components minimum
 173â†’     *   gray-500 (~0.55): ~4.6:1 -- normal text AA (borderline)
 174â†’     *   gray-600 (~0.45): ~7:1  -- normal text AA, comfortable
 175â†’     *   gray-700+:         ~10:1+ -- high contrast
 176â†’     *
 177â†’     * For text on light backgrounds, use gray-500 or darker for AA. */
 178â†’    --color-gray-50:  oklch(0.985 0 0); /* near-white backgrounds */
 179â†’    --color-gray-100: oklch(0.97 0 0);  /* subtle backgrounds, hover states */
 180â†’    --color-gray-200: oklch(0.925 0 0); /* borders, dividers */
 181â†’    --color-gray-300: oklch(0.87 0 0);  /* disabled text, emphasized borders */
 182â†’    --color-gray-400: oklch(0.71 0 0);  /* muted text (large only), icons */
 183â†’    --color-gray-500: oklch(0.55 0 0);  /* secondary text */
 184â†’    --color-gray-600: oklch(0.45 0 0);  /* body text */
 185â†’    --color-gray-700: oklch(0.37 0 0);  /* strong text */
 186â†’    --color-gray-800: oklch(0.27 0 0);  /* headings */
 187â†’    --color-gray-900: oklch(0.18 0 0);  /* near-black, high emphasis */
 188â†’
 189â†’    /* Primary -- blue for interactive elements.
 190â†’     * One blue. Used for links, buttons, focus rings. That's it.
 191â†’     * Hue 240, moderate chroma for a professional look. */
 192â†’    --color-primary-light: oklch(0.75 0.1 240);  /* hover states, light badges */
 193â†’    --color-primary:       oklch(0.55 0.18 240);  /* buttons, links, active states */
 194â†’    --color-primary-dark:  oklch(0.42 0.18 240);  /* pressed states, dark accents */
 195â†’
 196â†’    /* Semantic colors
 197â†’     * IMPORTANT: Color must never be the sole indicator of state.
 198â†’     * Every use of danger/success/warning must be paired with a
 199â†’     * secondary visual cue: icon, text label, strikethrough, border
 200â†’     * style change, etc. This is a WCAG requirement and team agreement. */
 201â†’    --color-danger:        oklch(0.55 0.2 25);   /* destructive actions, errors */
 202â†’    --color-danger-light:  oklch(0.92 0.04 25);  /* danger backgrounds */
 203â†’    --color-success:       oklch(0.6 0.17 145);  /* icons/indicators only -- ~3.9:1, fails AA for normal text */
 204â†’    --color-success-light: oklch(0.92 0.04 145); /* success backgrounds */
 205â†’    --color-warning:       oklch(0.75 0.15 75);  /* warnings */
 206â†’    --color-warning-light: oklch(0.93 0.04 75);  /* warning backgrounds */
 207â†’
 208â†’    /* Foreground / background semantic tokens */
 209â†’    --color-bg:            var(--color-gray-50);   /* page background */
 210â†’    --color-bg-raised:     white;                  /* cards, raised surfaces */
 211â†’    --color-fg:            var(--color-gray-800);  /* primary text */
 212â†’    --color-fg-muted:      var(--color-gray-600);  /* secondary text (~7.4:1 vs white -- comfortable AA for all text sizes) */
 213â†’    --color-fg-subtle:     var(--color-gray-400);  /* placeholders, hint text (3:1 -- NOT for body text) */
 214â†’    --color-border:        var(--color-gray-200);  /* default borders */
 215â†’    --color-border-strong: var(--color-gray-300);  /* emphasized borders, input focus */
 216â†’
 217â†’    /* ---- Typography ----
 218â†’     * System font stack -- no web font downloads, instant rendering.
 219â†’     * Fluid type scale using clamp() for smooth scaling between
 220â†’     * viewport sizes. Min at ~320px, max at ~1200px.
 221â†’     */
 222â†’    --font-sans: system-ui, -apple-system, "Segoe UI", Roboto,
 223â†’      "Helvetica Neue", Arial, sans-serif;
 224â†’
 225â†’    --font-mono: ui-monospace, "Cascadia Code", "Source Code Pro",
 226â†’      Menlo, Consolas, "DejaVu Sans Mono", monospace;
 227â†’
 228â†’    /* Fluid type scale
 229â†’     * clamp(min, preferred, max)
 230â†’     * Preferred uses viewport units for smooth scaling */
 231â†’    --font-size-xs:   clamp(0.6875rem, 0.65rem + 0.1vw, 0.75rem);     /* ~11-12px, fine print */
 232â†’    --font-size-sm:   clamp(0.8125rem, 0.78rem + 0.1vw, 0.875rem);    /* ~13-14px, captions */
 233â†’    --font-size-base: clamp(0.9375rem, 0.9rem + 0.12vw, 1rem);        /* ~15-16px, body text */
 234â†’    --font-size-lg:   clamp(1.0625rem, 1rem + 0.15vw, 1.125rem);      /* ~17-18px, subheadings */
 235â†’    --font-size-xl:   clamp(1.1875rem, 1.1rem + 0.2vw, 1.3125rem);    /* ~19-21px, section headings */
 236â†’    --font-size-2xl:  clamp(1.4375rem, 1.3rem + 0.3vw, 1.625rem);     /* ~23-26px, page headings */
 237â†’    --font-size-3xl:  clamp(1.75rem, 1.6rem + 0.4vw, 2.125rem);       /* ~28-34px, hero/display */
 238â†’
 239â†’    /* Line heights */
 240â†’    --leading-tight:   1.25;   /* headings */
 241â†’    --leading-snug:    1.375;  /* subheadings, large text */
 242â†’    --leading-normal:  1.5;    /* body text */
 243â†’    --leading-relaxed: 1.625;  /* small text that needs more air */
 244â†’
 245â†’    /* Font weights */
 246â†’    --font-normal:    400;
 247â†’    --font-medium:    500;
 248â†’    --font-semibold:  600;
 249â†’    --font-bold:      700;
 250â†’
 251â†’    /* ---- Shadows ----
 252â†’     * Three levels. Shadows use oklch for consistency with the color system.
 253â†’     * Never combine shadows and borders on the same element (per team agreement).
 254â†’     */
 255â†’    --shadow-sm:  0 1px 2px oklch(0.18 0 0 / 0.05);
 256â†’    --shadow-md:  0 4px 6px -1px oklch(0.18 0 0 / 0.07),
 257â†’                  0 2px 4px -2px oklch(0.18 0 0 / 0.05);
 258â†’    --shadow-lg:  0 10px 15px -3px oklch(0.18 0 0 / 0.08),
 259â†’                  0 4px 6px -4px oklch(0.18 0 0 / 0.04);
 260â†’
 261â†’    /* ---- Border Radius ---- */
 262â†’    --radius-sm:   0.25rem;  /* 4px -- badges, tags */
 263â†’    --radius-md:   0.5rem;   /* 8px -- buttons, inputs, cards */
 264â†’    --radius-lg:   0.75rem;  /* 12px -- larger containers, modals */
 265â†’    --radius-full: 9999px;   /* pills, avatars */
 266â†’
 267â†’    /* ---- Transition Durations ----
 268â†’     * Motion-safe by default: tokens are 0s unless the user has no
 269â†’     * motion preference. This means developers can use transition
 270â†’     * tokens without needing to remember the media query wrapper --
 271â†’     * the tokens themselves are inert when reduced motion is active.
 272â†’     * The reset layer catch-all (prefers-reduced-motion: reduce) is
 273â†’     * a secondary safety net.
 274â†’     * Easing: ease (not ease-in-out).
 275â†’     */
 276â†’    --transition-fast:   0s;
 277â†’    --transition-normal: 0s;
 278â†’    --transition-slow:   0s;
 279â†’
 280â†’    /* ---- Focus Ring ----
 281â†’     * Reusable focus ring properties for consistent :focus-visible styles.
 282â†’     * 3:1+ contrast against background (blue on white/light gray).
 283â†’     */
 284â†’    --focus-ring-color:  var(--color-primary);
 285â†’    --focus-ring-offset: 2px;
 286â†’    --focus-ring-width:  2px;
 287â†’  }
 288â†’
 289â†’  /* Activate transition durations only when user has no motion preference */
 290â†’  @media (prefers-reduced-motion: no-preference) {
 291â†’    :root {
 292â†’      --transition-fast:   100ms;  /* micro-interactions: hover, focus */
 293â†’      --transition-normal: 200ms;  /* standard: expand, slide */
 294â†’      --transition-slow:   300ms;  /* larger: modal, page */
 295â†’    }
 296â†’  }
 297â†’}
 298â†’
 299â†’/* ==========================================================================
 300â†’   BASE LAYER
 301â†’   Element-level styles applied directly to HTML elements.
 302â†’   No classes -- this establishes the typographic and interactive baseline.
 303â†’   ========================================================================== */
 304â†’
 305â†’@layer base {
 306â†’  body {
 307â†’    font-family: var(--font-sans);
 308â†’    font-size: var(--font-size-base);
 309â†’    font-weight: var(--font-normal);
 310â†’    line-height: var(--leading-normal);
 311â†’    color: var(--color-fg);
 312â†’    background-color: var(--color-bg);
 313â†’  }
 314â†’
 315â†’  /* Headings -- tighter line-height, bolder weight, type scale */
 316â†’  h1 {
 317â†’    font-size: var(--font-size-3xl);
 318â†’    font-weight: var(--font-bold);
 319â†’    line-height: var(--leading-tight);
 320â†’  }
 321â†’
 322â†’  h2 {
 323â†’    font-size: var(--font-size-2xl);
 324â†’    font-weight: var(--font-bold);
 325â†’    line-height: var(--leading-tight);
 326â†’  }
 327â†’
 328â†’  h3 {
 329â†’    font-size: var(--font-size-xl);
 330â†’    font-weight: var(--font-semibold);
 331â†’    line-height: var(--leading-snug);
 332â†’  }
 333â†’
 334â†’  h4 {
 335â†’    font-size: var(--font-size-lg);
 336â†’    font-weight: var(--font-semibold);
 337â†’    line-height: var(--leading-snug);
 338â†’  }
 339â†’
 340â†’  h5,
 341â†’  h6 {
 342â†’    font-size: var(--font-size-base);
 343â†’    font-weight: var(--font-medium);
 344â†’    line-height: var(--leading-snug);
 345â†’  }
 346â†’
 347â†’  /* Links */
 348â†’  a {
 349â†’    color: var(--color-primary);
 350â†’    text-decoration: underline;
 351â†’    text-underline-offset: 0.15em;
 352â†’
 353â†’    &:hover {
 354â†’      color: var(--color-primary-dark);
 355â†’    }
 356â†’  }
 357â†’
 358â†’  /* Focus-visible styles for all interactive elements.
 359â†’   * Uses outline for keyboard focus, visible only on keyboard navigation.
 360â†’   * Double-ring technique: white inner ring (box-shadow) + colored outer ring
 361â†’   * (outline) ensures visibility on both light and dark backgrounds.
 362â†’   * 3:1+ contrast ratio maintained in all contexts. */
 363â†’  :focus-visible {
 364â†’    outline: var(--focus-ring-width) solid var(--focus-ring-color);
 365â†’    outline-offset: var(--focus-ring-offset);
 366â†’    box-shadow: 0 0 0 var(--focus-ring-offset) white;
 367â†’  }
 368â†’
 369â†’  /* Buttons -- base styles, ready for component overrides */
 370â†’  button,
 371â†’  [type="button"],
 372â†’  [type="submit"],
 373â†’  [type="reset"] {
 374â†’    display: inline-flex;
 375â†’    align-items: center;
 376â†’    justify-content: center;
 377â†’    gap: var(--space-sm);
 378â†’    padding-block: var(--space-sm);
 379â†’    padding-inline: var(--space-md);
 380â†’    font-size: var(--font-size-base);
 381â†’    font-weight: var(--font-medium);
 382â†’    line-height: var(--leading-tight);
 383â†’    border-radius: var(--radius-md);
 384â†’    background-color: var(--color-primary);
 385â†’    color: white;
 386â†’
 387â†’    &:hover {
 388â†’      background-color: var(--color-primary-dark);
 389â†’    }
 390â†’  }
 391â†’
 392â†’  @media (prefers-reduced-motion: no-preference) {
 393â†’    button,
 394â†’    [type="button"],
 395â†’    [type="submit"],
 396â†’    [type="reset"] {
 397â†’      transition: background-color var(--transition-fast) ease;
 398â†’    }
 399â†’  }
 400â†’
 401â†’  /* Form inputs */
 402â†’  input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
 403â†’  textarea,
 404â†’  select {
 405â†’    display: block;
 406â†’    inline-size: 100%;
 407â†’    padding-block: var(--space-sm);
 408â†’    padding-inline: var(--space-3);
 409â†’    font-size: var(--font-size-base);
 410â†’    line-height: var(--leading-normal);
 411â†’    color: var(--color-fg);
 412â†’    background-color: var(--color-bg-raised);
 413â†’    border: 1px solid var(--color-border);
 414â†’    border-radius: var(--radius-md);
 415â†’
 416â†’    &::placeholder {
 417â†’      color: var(--color-fg-subtle);
 418â†’    }
 419â†’  }
 420â†’
 421â†’  /* Invalid inputs -- danger border for any input with aria-invalid */
 422â†’  [aria-invalid="true"] {
 423â†’    border-color: var(--color-danger);
 424â†’  }
 425â†’
 426â†’  /* Labels */
 427â†’  label {
 428â†’    display: block;
 429â†’    font-size: var(--font-size-sm);
 430â†’    font-weight: var(--font-medium);
 431â†’    color: var(--color-fg);
 432â†’  }
 433â†’
 434â†’  /* Fieldset */
 435â†’  fieldset {
 436â†’    border: none;
 437â†’  }
 438â†’
 439â†’  /* Code */
 440â†’  code,
 441â†’  pre {
 442â†’    font-family: var(--font-mono);
 443â†’    font-size: var(--font-size-sm);
 444â†’  }
 445â†’
 446â†’  /* Windows High Contrast Mode support.
 447â†’   * In forced-colors mode, the browser overrides most colors.
 448â†’   * We ensure borders, outlines, and structural indicators remain
 449â†’   * visible since they become the primary way to distinguish elements. */
 450â†’  @media (forced-colors: active) {
 451â†’    button,
 452â†’    [type="button"],
 453â†’    [type="submit"],
 454â†’    [type="reset"] {
 455â†’      border: 1px solid ButtonText;
 456â†’    }
 457â†’
 458â†’    input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
 459â†’    textarea,
 460â†’    select {
 461â†’      border: 1px solid ButtonText;
 462â†’    }
 463â†’
 464â†’    :focus-visible {
 465â†’      outline: 2px solid Highlight;
 466â†’      outline-offset: 2px;
 467â†’    }
 468â†’  }
 469â†’}
 470â†’
 471â†’/* ==========================================================================
 472â†’   LAYOUT LAYER
 473â†’   Page-level layout using CSS Grid. Mobile-first, desktop breakpoint ~1024px.
 474â†’   Uses logical properties for RTL support.
 475â†’   ========================================================================== */
 476â†’
 477â†’@layer layout {
 478â†’  /* Page layout: header / main / footer with sticky footer */
 479â†’  .page-layout {
 480â†’    display: grid;
 481â†’    grid-template-rows: auto 1fr auto;
 482â†’    min-block-size: 100vh;
 483â†’  }
 484â†’
 485â†’  /* Constrained content container */
 486â†’  .container {
 487â†’    inline-size: 100%;
 488â†’    max-inline-size: 40rem; /* ~640px -- a todo list is narrow */
 489â†’    margin-inline: auto;
 490â†’    padding-inline: var(--space-md);
 491â†’  }
 492â†’
 493â†’  /* Wider container variant for pages that need more space */
 494â†’  .container--wide {
 495â†’    max-inline-size: 64rem; /* ~1024px */
 496â†’  }
 497â†’
 498â†’  /* Responsive adjustments */
 499â†’  @media (min-width: 1024px) {
 500â†’    .container {
 501â†’      padding-inline: var(--space-lg);
 502â†’    }
 503â†’  }
 504â†’
 505â†’  /* Container query setup -- components can respond to their container */
 506â†’  .component-container {
 507â†’    container-type: inline-size;
 508â†’  }
 509â†’}
 510â†’
 511â†’/* ==========================================================================
 512â†’   COMPONENTS LAYER
 513â†’   Component-specific styles are added here as features are built.
 514â†’   Each component should be self-contained and reference only design tokens.
 515â†’   ========================================================================== */
 516â†’
 517â†’@layer components {
 518â†’  /* ---- HTMX Indicators ----
 519â†’   * .htmx-indicator elements are hidden by default and revealed when
 520â†’   * HTMX adds .htmx-request to a requesting element or its parent.
 521â†’   * Used for inline loading spinners/text during server requests.
 522â†’   * See: https://htmx.org/attributes/hx-indicator/ */
 523â†’  .htmx-indicator {
 524â†’    opacity: 0;
 525â†’    transition: opacity var(--transition-normal) ease;
 526â†’  }
 527â†’
 528â†’  .htmx-request .htmx-indicator,
 529â†’  .htmx-request.htmx-indicator {
 530â†’    opacity: 1;
 531â†’  }
 532â†’
 533â†’  /* ---- Auth Form ----
 534â†’   * Used for registration, login, and similar auth-related forms.
 535â†’   * Centered, constrained-width form with vertical field stacking. */
 536â†’  .auth-form {
 537â†’    max-inline-size: 24rem;
 538â†’    margin-inline: auto;
 539â†’    padding-block-start: var(--space-2xl);
 540â†’  }
 541â†’
 542â†’  .auth-form h1 {
 543â†’    margin-block-end: var(--space-lg);
 544â†’  }
 545â†’
 546â†’  .auth-form__fields {
 547â†’    display: flex;
 548â†’    flex-direction: column;
 549â†’    gap: var(--space-lg);
 550â†’  }
 551â†’
 552â†’  .auth-form__group {
 553â†’    display: flex;
 554â†’    flex-direction: column;
 555â†’    gap: var(--space-xs);
 556â†’  }
 557â†’
 558â†’
 559â†’  .auth-form__error {
 560â†’    color: var(--color-danger);
 561â†’    font-size: var(--font-size-sm);
 562â†’  }
 563â†’
 564â†’  .auth-form__hint {
 565â†’    font-size: var(--font-size-xs);
 566â†’    color: var(--color-fg-muted);
 567â†’  }
 568â†’
 569â†’  /* Password visibility toggle -- JS progressive enhancement */
 570â†’  .password-toggle {
 571â†’    background: none;
 572â†’    border: none;
 573â†’    padding: 0;
 574â†’    border-radius: 0;
 575â†’    color: var(--color-primary);
 576â†’    font-size: var(--font-size-xs);
 577â†’    font-weight: var(--font-normal);
 578â†’    cursor: pointer;
 579â†’    text-decoration: underline;
 580â†’    text-underline-offset: 0.15em;
 581â†’  }
 582â†’
 583â†’  .password-toggle:hover {
 584â†’    background: none;
 585â†’    color: var(--color-primary-dark);
 586â†’  }
 587â†’
 588â†’  .auth-form__message {
 589â†’    padding: var(--space-sm) var(--space-md);
 590â†’    border-radius: var(--radius-md);
 591â†’    font-size: var(--font-size-sm);
 592â†’    margin-block-end: var(--space-lg);
 593â†’  }
 594â†’
 595â†’  /* Collapse empty message containers so they don't leave a gap */
 596â†’  .auth-form__message:empty {
 597â†’    display: none;
 598â†’  }
 599â†’
 600â†’  .auth-form__message--error {
 601â†’    background-color: var(--color-danger-light);
 602â†’    color: var(--color-danger);
 603â†’  }
 604â†’
 605â†’  .auth-form__submit {
 606â†’    inline-size: 100%;
 607â†’  }
 608â†’
 609â†’  /* Actions row (save + cancel) for edit forms */
 610â†’  .auth-form__actions {
 611â†’    display: flex;
 612â†’    align-items: center;
 613â†’    gap: var(--space-md);
 614â†’  }
 615â†’
 616â†’  /* Cancel link styled as secondary text action */
 617â†’  .auth-form__cancel {
 618â†’    font-size: var(--font-size-sm);
 619â†’    color: var(--color-fg-muted);
 620â†’  }
 621â†’
 622â†’  .auth-form__cancel:hover {
 623â†’    color: var(--color-fg);
 624â†’  }
 625â†’
 626â†’  .auth-form__footer {
 627â†’    margin-block-start: var(--space-lg);
 628â†’    text-align: center;
 629â†’    font-size: var(--font-size-sm);
 630â†’    color: var(--color-fg-muted);
 631â†’  }
 632â†’
 633â†’  /* ---- Site Header ----
 634â†’   * Authenticated page header with brand link and user actions (logout).
 635â†’   * Flexbox layout: brand left, actions right. */
 636â†’  .site-header {
 637â†’    display: flex;
 638â†’    align-items: center;
 639â†’    justify-content: space-between;
 640â†’    padding-block: var(--space-md);
 641â†’  }
 642â†’
 643â†’  .site-header__brand {
 644â†’    font-weight: var(--font-semibold);
 645â†’    color: var(--color-fg);
 646â†’    text-decoration: none;
 647â†’  }
 648â†’
 649â†’  .site-header__actions {
 650â†’    display: flex;
 651â†’    align-items: center;
 652â†’    gap: var(--space-md);
 653â†’    font-size: var(--font-size-sm);
 654â†’    color: var(--color-fg-muted);
 655â†’  }
 656â†’
 657â†’  /* ---- Text Button ----
 658â†’   * Button styled as a text link. Used for logout and other
 659â†’   * non-primary actions that are semantically form submissions. */
 660â†’  .button--text {
 661â†’    background: none;
 662â†’    border: none;
 663â†’    color: var(--color-fg-muted);
 664â†’    font-size: var(--font-size-sm);
 665â†’    font-weight: var(--font-normal);
 666â†’    padding: 0;
 667â†’    border-radius: 0;
 668â†’    cursor: pointer;
 669â†’  }
 670â†’
 671â†’  .button--text:hover {
 672â†’    background: none;
 673â†’    color: var(--color-fg);
 674â†’    text-decoration: underline;
 675â†’  }
 676â†’
 677â†’  /* ---- Nav Logout ----
 678â†’   * Logout form positioned to the right side of the header nav.
 679â†’   * The button is styled as a text link, not a primary button. */
 680â†’  .nav-logout {
 681â†’    margin-inline-start: auto;
 682â†’  }
 683â†’
 684â†’  .nav-logout__button {
 685â†’    background: none;
 686â†’    border: none;
 687â†’    color: var(--color-fg-muted);
 688â†’    font-size: var(--font-size-sm);
 689â†’    font-weight: var(--font-normal);
 690â†’    padding: 0;
 691â†’    border-radius: 0;
 692â†’    cursor: pointer;
 693â†’  }
 694â†’
 695â†’  .nav-logout__button:hover {
 696â†’    background: none;
 697â†’    color: var(--color-fg);
 698â†’    text-decoration: underline;
 699â†’  }
 700â†’
 701â†’  /* ---- Todo Add Form ----
 702â†’   * Prominent input at top of todo list for adding new items.
 703â†’   * Label above, input + button row below. */
 704â†’  .todo-add {
 705â†’    margin-block: var(--space-lg);
 706â†’  }
 707â†’
 708â†’  .todo-add__group {
 709â†’    margin-block-end: var(--space-xs);
 710â†’  }
 711â†’
 712â†’  .todo-add__label {
 713â†’    display: block;
 714â†’    font-size: var(--font-size-sm);
 715â†’    font-weight: var(--font-medium);
 716â†’    margin-block-end: var(--space-xs);
 717â†’  }
 718â†’
 719â†’  .todo-add__row {
 720â†’    display: flex;
 721â†’    gap: var(--space-sm);
 722â†’  }
 723â†’
 724â†’  .todo-add__input {
 725â†’    flex: 1;
 726â†’  }
 727â†’
 728â†’  .todo-add__submit {
 729â†’    flex-shrink: 0;
 730â†’  }
 731â†’
 732â†’  /* Error text for the add-todo form (always in DOM for aria-describedby) */
 733â†’  .todo-add__error {
 734â†’    color: var(--color-danger);
 735â†’    font-size: var(--font-size-sm);
 736â†’  }
 737â†’
 738â†’  .todo-add__error:empty {
 739â†’    display: none;
 740â†’  }
 741â†’
 742â†’  /* ---- Todo List ----
 743â†’   * Vertical list of todo items separated by borders.
 744â†’   * Each item is a flex row: checkbox + label (title). */
 745â†’  .todo-list {
 746â†’    display: flex;
 747â†’    flex-direction: column;
 748â†’  }
 749â†’
 750â†’  .todo-item {
 751â†’    display: flex;
 752â†’    align-items: center;
