 757â†’  }
 758â†’
 759â†’  .todo-item:first-child {
 760â†’    border-block-start: 1px solid var(--color-border);
 761â†’  }
 762â†’
 763â†’  /* Toggle button -- styled as minimal inline button for completion toggle */
 764â†’  .todo-item__toggle {
 765â†’    background: none;
 766â†’    border: none;
 767â†’    padding: var(--space-xs);
