 791â†’  }
 792â†’
 793â†’  /* Delete trigger -- the summary element styled as a small muted button */
 794â†’  .todo-item__delete {
 795â†’    background: none;
 796â†’    border: none;
 797â†’    padding: var(--space-xs);
 798â†’    cursor: pointer;
 799â†’    color: var(--color-fg-muted);
 800â†’    font-size: var(--font-size-sm);
 801â†’    list-style: none;
 802â†’  }
