 816â†’    align-items: center;
 817â†’    gap: var(--space-xs);
 818â†’  }
 819â†’
 820â†’  .todo-item__delete-confirm[open] > form {
 821â†’    display: flex;
 822â†’    align-items: center;
 823â†’    gap: var(--space-xs);
 824â†’  }
 825â†’
 826â†’  .todo-item__delete-confirm[open] > form span {
 827â†’    font-size: var(--font-size-xs);
 828â†’    color: var(--color-fg-muted);
 829â†’    white-space: nowrap;
 830â†’  }
 831â†’
 832â†’  .todo-item__delete-yes {
 833â†’    font-size: var(--font-size-xs);
 834â†’    padding: var(--space-xs) var(--space-sm);
 835â†’    background-color: var(--color-danger);
 836â†’    color: white;
 837â†’    border: none;
 838â†’    border-radius: var(--radius-sm);
 839â†’    cursor: pointer;
 840â†’  }
 841â†’
 842â†’  .todo-item__delete-yes:hover {
 843â†’    background-color: var(--color-danger-dark, oklch(0.45 0.2 25));
 844â†’  }
 845â†’
 846â†’  /* ---- Edit Mode ----
 847â†’   * Pencil icon button triggers edit mode (US-8). No-JS baseline
 848â†’   * navigates to an edit page; HTMX swaps inline. */
 849â†’  .todo-item__edit {
 850â†’    background: none;
 851â†’    border: none;
 852â†’    padding: var(--space-xs);
 853â†’    cursor: pointer;
 854â†’    color: var(--color-fg-muted);
 855â†’    font-size: var(--font-size-sm);
 856â†’    flex-shrink: 0;
 857â†’  }
 858â†’
 859â†’  .todo-item__edit:hover {
