 874â†’    min-inline-size: 0;
 875â†’    font-size: var(--font-size-base);
 876â†’    padding: var(--space-xs) var(--space-sm);
 877â†’  }
 878â†’
 879â†’  .todo-item__edit-save,
 880â†’  .todo-item__edit-cancel {
 881â†’    font-size: var(--font-size-xs);
 882â†’    padding: var(--space-xs) var(--space-sm);
 883â†’    border: none;
 884â†’    border-radius: var(--radius-sm);
 885â†’    cursor: pointer;
 886â†’    flex-shrink: 0;
 887â†’  }
 888â†’
 889â†’  .todo-item__edit-save {
 890â†’    background-color: var(--color-primary);
 891â†’    color: white;
 892â†’  }
 893â†’
 894â†’  .todo-item__edit-cancel {
 895â†’    background: none;
 896â†’    color: var(--color-fg-muted);
 897â†’  }
 898â†’
 899â†’  .todo-item__edit-cancel:hover {
 900â†’    color: var(--color-fg);
 901â†’  }
 902â†’
 903â†’  /* ---- Landing Hero ----
 904â†’   * Centered landing page content for unauthenticated visitors.
 905â†’   * Matches auth-form width (24rem) for visual consistency. */
 906â†’  .landing-hero {
 907â†’    max-inline-size: 24rem;
 908â†’    margin-inline: auto;
 909â†’    padding-block-start: var(--space-3xl);
 910â†’    text-align: center;
 911â†’  }
 912â†’
 913â†’  .landing-hero h1 {
 914â†’    margin-block-end: var(--space-sm);
 915â†’  }
 916â†’
 917â†’  .landing-hero p {
