 928â†’
 929â†’  .landing-hero__cta {
 930â†’    display: inline-flex;
 931â†’    align-items: center;
 932â†’    justify-content: center;
 933â†’    inline-size: 100%;
 934â†’    padding-block: var(--space-sm);
 935â†’    padding-inline: var(--space-xl);
 936â†’    background-color: var(--color-primary);
 937â†’    color: white;
 938â†’    text-decoration: none;
 939â†’    border-radius: var(--radius-md);
 940â†’    font-weight: var(--font-medium);
 941â†’  }
 942â†’
 943â†’  .landing-hero__cta:hover {
 944â†’    background-color: var(--color-primary-dark);
 945â†’    color: white;
 946â†’  }
 947â†’
 948â†’  @media (prefers-reduced-motion: no-preference) {
 949â†’    .landing-hero__cta {
 950â†’      transition: background-color var(--transition-fast) ease;
 951â†’    }
 952â†’  }
 953â†’
 954â†’  .landing-hero__alt {
 955â†’    font-size: var(--font-size-sm);
 956â†’    color: var(--color-fg-muted);
 957â†’  }
 958â†’
 959â†’  /* ---- Empty State ---- */
 960â†’  .todo-empty {
 961â†’    color: var(--color-fg-muted);
 962â†’    font-size: var(--font-size-sm);
 963â†’    text-align: center;
 964â†’    padding-block: var(--space-xl);
 965â†’  }
 966â†’}
 967â†’
 968â†’/* ==========================================================================
 969â†’   UTILITIES LAYER
 970â†’   Helper classes. These have the highest layer priority.
 971â†’   ========================================================================== */
 972â†’
 973â†’@layer utilities {
 974â†’  /* Visually hidden -- accessible to screen readers but not visible.
 975â†’   * Uses the clip technique for reliable hiding.
 976â†’   * white-space: nowrap prevents content from being announced as
 977â†’   * multiple separate items by some screen readers. */
 978â†’  .visually-hidden,
 979â†’  .sr-only {
 980â†’    position: absolute;
 981â†’    inline-size: 1px;
 982â†’    block-size: 1px;
 983â†’    padding: 0;
 984â†’    margin: -1px;
 985â†’    overflow: hidden;
 986â†’    clip: rect(0 0 0 0);
 987â†’    clip-path: inset(50%);
 988â†’    white-space: nowrap;
 989â†’    border: 0;
 990â†’  }
 991â†’
 992â†’  /* Skip link -- visually hidden until focused, then revealed.
 993â†’   * Keyboard users tab to this first and see it appear at the
 994â†’   * top of the page. Uses the base template's skip link:
 995â†’   * <a href="#main-content" class="skip-link">Skip to main content</a> */
 996â†’  .skip-link {
 997â†’    position: absolute;
 998â†’    inline-size: 1px;
 999â†’    block-size: 1px;
1000â†’    padding: 0;
1001â†’    margin: -1px;
1002â†’    overflow: hidden;
1003â†’    clip: rect(0 0 0 0);
1004â†’    clip-path: inset(50%);
1005â†’    white-space: nowrap;
1006â†’    border: 0;
1007â†’
1008â†’    &:focus-visible {
1009â†’      position: fixed;
1010â†’      inset-block-start: var(--space-sm);
1011â†’      inset-inline-start: var(--space-sm);
1012â†’      z-index: 9999;
1013â†’      inline-size: auto;
1014â†’      block-size: auto;
1015â†’      padding: var(--space-sm) var(--space-md);
1016â†’      margin: 0;
1017â†’      overflow: visible;
1018â†’      clip: auto;
1019â†’      clip-path: none;
1020â†’      white-space: normal;
1021â†’      background-color: var(--color-primary);
1022â†’      color: white;
1023â†’      font-size: var(--font-size-sm);
1024â†’      font-weight: var(--font-medium);
1025â†’      border-radius: var(--radius-md);
1026â†’      box-shadow: var(--shadow-md);
1027â†’    }
1028â†’  }
1029â†’}
1030â†’

